select r.role_code, r.role_type,g.* from app_auth_role r left join app_auth_permission g on r.application_id = g.application_id and r.role_uuid = g.role_uuid where r.deleted = 0 and (g.deleted = 0 or g.deleted is null) and r.application_id = #{applicationId}
#{item}
and (g.menu_id = #{menuId} or g.menu_id is null)
